"use client"

import { useState } from "react"
import { useRouter } from "next/navigation"
import Link from "next/link"
import { useStore } from "@/store"
import { api } from "@/lib/api"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Card, CardHeader, CardTitle, CardDescription, CardContent } from "@/components/ui/card"
import { User, Shield, Users, Eye, Mail, CheckCircle, ArrowLeft, Home } from "lucide-react"

type Step = "email" | "otp" | "details"

export default function RegisterPage() {
  const [step, setStep] = useState<Step>("email")
  const [email, setEmail] = useState("")
  const [otp, setOtp] = useState("")
  const [name, setName] = useState("")
  const [password, setPassword] = useState("")
  const [confirmPassword, setConfirmPassword] = useState("")
  const [role, setRole] = useState("member")
  const [error, setError] = useState("")
  const [loading, setLoading] = useState(false)
  const [otpSent, setOtpSent] = useState(false)
  const { register } = useStore()
  const router = useRouter()

  const handleSendOtp = async (e: React.FormEvent) => {
    e.preventDefault()
    setError("")
    setLoading(true)

    try {
      await api.sendOtp(email)
      setOtpSent(true)
      setStep("otp")
    } catch (err: any) {
      setError(err.message || "Failed to send OTP")
    } finally {
      setLoading(false)
    }
  }

  const handleVerifyOtp = async (e: React.FormEvent) => {
    e.preventDefault()
    setError("")
    setLoading(true)

    try {
      await api.verifyOtp(email, otp)
      setStep("details")
    } catch (err: any) {
      setError(err.message || "Invalid OTP")
    } finally {
      setLoading(false)
    }
  }

  const handleResendOtp = async () => {
    setError("")
    setLoading(true)

    try {
      await api.resendOtp(email)
      setError("")
      alert("OTP resent successfully!")
    } catch (err: any) {
      setError(err.message || "Failed to resend OTP")
    } finally {
      setLoading(false)
    }
  }

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault()
    setError("")

    if (password !== confirmPassword) {
      setError("Passwords do not match")
      return
    }

    if (password.length < 6) {
      setError("Password must be at least 6 characters")
      return
    }

    setLoading(true)

    try {
      await register(email, password, name)
      router.push("/dashboard")
    } catch (err: any) {
      setError(err.message || "Registration failed")
    } finally {
      setLoading(false)
    }
  }

  const roles = [
    { id: "admin", label: "Admin", icon: Shield, description: "Full access to manage organization" },
    { id: "member", label: "Member", icon: Users, description: "Can create and manage tasks" },
    { id: "guest", label: "Guest", icon: Eye, description: "Read-only access to shared resources" },
  ]

  return (
    <div className="min-h-screen flex items-center justify-center p-4 bg-gradient-to-br from-blue-50 to-indigo-100">
      <Card className="w-full max-w-md shadow-xl border-0">
        <CardHeader className="text-center pb-2">
          <div className="mx-auto w-12 h-12 bg-blue-600 rounded-full flex items-center justify-center mb-4">
            {step === "email" && <Mail className="h-6 w-6 text-white" />}
            {step === "otp" && <CheckCircle className="h-6 w-6 text-white" />}
            {step === "details" && <User className="h-6 w-6 text-white" />}
          </div>
          <CardTitle className="text-2xl text-gray-900">
            {step === "email" && "Create Account"}
            {step === "otp" && "Verify Email"}
            {step === "details" && "Complete Profile"}
          </CardTitle>
          <CardDescription className="text-gray-600">
            {step === "email" && "Enter your email to get started"}
            {step === "otp" && `Enter the 6-digit code sent to ${email}`}
            {step === "details" && "Fill in your details to complete registration"}
          </CardDescription>
        </CardHeader>
        <CardContent>
          {/* Step indicator */}
          <div className="flex items-center justify-center gap-2 mb-6">
            <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-medium ${
              step === "email" ? "bg-blue-600 text-white" : "bg-green-500 text-white"
            }`}>
              {step === "email" ? "1" : "✓"}
            </div>
            <div className={`w-12 h-1 ${step !== "email" ? "bg-green-500" : "bg-gray-200"}`} />
            <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-medium ${
              step === "otp" ? "bg-blue-600 text-white" : step === "details" ? "bg-green-500 text-white" : "bg-gray-200 text-gray-500"
            }`}>
              {step === "details" ? "✓" : "2"}
            </div>
            <div className={`w-12 h-1 ${step === "details" ? "bg-green-500" : "bg-gray-200"}`} />
            <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-medium ${
              step === "details" ? "bg-blue-600 text-white" : "bg-gray-200 text-gray-500"
            }`}>
              3
            </div>
          </div>

          {error && (
            <div className="p-3 bg-red-50 text-red-700 text-sm rounded-md border border-red-200 mb-4">
              {error}
            </div>
          )}

          {/* Step 1: Email */}
          {step === "email" && (
            <form onSubmit={handleSendOtp} className="space-y-4">
              <div>
                <label className="text-sm font-medium text-gray-700">Email Address</label>
                <Input
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  placeholder="you@example.com"
                  required
                  className="mt-1 bg-white text-gray-900 border-gray-300"
                />
              </div>
              <Button type="submit" className="w-full bg-blue-600 hover:bg-blue-700 text-white" disabled={loading}>
                {loading ? "Sending OTP..." : "Send Verification Code"}
              </Button>
            </form>
          )}

          {/* Step 2: OTP Verification */}
          {step === "otp" && (
            <form onSubmit={handleVerifyOtp} className="space-y-4">
              <div>
                <label className="text-sm font-medium text-gray-700">Verification Code</label>
                <Input
                  type="text"
                  value={otp}
                  onChange={(e) => setOtp(e.target.value.replace(/\D/g, '').slice(0, 6))}
                  placeholder="Enter 6-digit code"
                  required
                  maxLength={6}
                  className="mt-1 bg-white text-gray-900 border-gray-300 text-center text-2xl tracking-widest"
                />
              </div>
              <Button type="submit" className="w-full bg-blue-600 hover:bg-blue-700 text-white" disabled={loading || otp.length !== 6}>
                {loading ? "Verifying..." : "Verify Code"}
              </Button>
              <div className="flex items-center justify-between text-sm">
                <button
                  type="button"
                  onClick={() => setStep("email")}
                  className="text-gray-600 hover:text-gray-900 flex items-center gap-1"
                >
                  <ArrowLeft className="h-4 w-4" /> Change email
                </button>
                <button
                  type="button"
                  onClick={handleResendOtp}
                  className="text-blue-600 hover:underline"
                  disabled={loading}
                >
                  Resend code
                </button>
              </div>
            </form>
          )}

          {/* Step 3: Profile Details */}
          {step === "details" && (
            <form onSubmit={handleRegister} className="space-y-4">
              <div className="p-3 bg-green-50 text-green-700 text-sm rounded-md border border-green-200 flex items-center gap-2">
                <CheckCircle className="h-4 w-4" />
                Email verified: {email}
              </div>
              
              <div>
                <label className="text-sm font-medium text-gray-700">Full Name</label>
                <Input
                  type="text"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  placeholder="John Doe"
                  required
                  className="mt-1 bg-white text-gray-900 border-gray-300"
                />
              </div>
              
              <div>
                <label className="text-sm font-medium text-gray-700">Password</label>
                <Input
                  type="password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="••••••••"
                  required
                  minLength={6}
                  className="mt-1 bg-white text-gray-900 border-gray-300"
                />
              </div>
              
              <div>
                <label className="text-sm font-medium text-gray-700">Confirm Password</label>
                <Input
                  type="password"
                  value={confirmPassword}
                  onChange={(e) => setConfirmPassword(e.target.value)}
                  placeholder="••••••••"
                  required
                  minLength={6}
                  className="mt-1 bg-white text-gray-900 border-gray-300"
                />
              </div>
              
              <div>
                <label className="text-sm font-medium text-gray-700 mb-2 block">Select Your Role</label>
                <div className="grid grid-cols-3 gap-2">
                  {roles.map((r) => {
                    const Icon = r.icon
                    return (
                      <button
                        key={r.id}
                        type="button"
                        onClick={() => setRole(r.id)}
                        className={`p-3 rounded-lg border-2 transition-all ${
                          role === r.id
                            ? "border-blue-600 bg-blue-50"
                            : "border-gray-200 bg-white hover:border-gray-300"
                        }`}
                      >
                        <Icon className={`h-5 w-5 mx-auto mb-1 ${role === r.id ? "text-blue-600" : "text-gray-500"}`} />
                        <p className={`text-xs font-medium ${role === r.id ? "text-blue-700" : "text-gray-700"}`}>
                          {r.label}
                        </p>
                      </button>
                    )
                  })}
                </div>
                <p className="text-xs text-gray-500 mt-2 text-center">
                  {roles.find(r => r.id === role)?.description}
                </p>
              </div>

              <Button type="submit" className="w-full bg-blue-600 hover:bg-blue-700 text-white" disabled={loading}>
                {loading ? "Creating account..." : "Create Account"}
              </Button>
            </form>
          )}

          <p className="text-center text-sm text-gray-600 mt-4">
            Already have an account?{" "}
            <Link href="/login" className="text-blue-600 hover:underline font-medium">
              Sign in
            </Link>
          </p>
          <div className="mt-4 pt-4 border-t border-gray-200">
            <Link href="/">
              <Button variant="outline" className="w-full text-gray-600 hover:text-gray-900">
                <Home className="h-4 w-4 mr-2" />
                Back to Home
              </Button>
            </Link>
          </div>
        </CardContent>
      </Card>
    </div>
  )
}
